console.log(JSON.stringify(summaries_tjalda, null, 2));")

repl("Estimating daily driving times with map routing", "async function osrmRouteTime2(points) {
  const coords = points.map(p => `${p[1]},${p[0]}`).join(';');
  const url = `https://router.project-osrm.org/route/v1/driving/${coords}?overview=false&alternatives=false&steps=false`;
  const r = await fetch(url);
  const data = await r.json();
  if (!data.routes) return {error:data, url};
  return {seconds:data.routes[0].duration, km:data.routes[0].distance/1000, url};
}
const pts_route = {
  Reykjavik:[64.1466,-21.9426], Thingvellir:[64.2559,-21.1295], Geysir:[64.3104,-20.3024], Gullfoss:[64.3271,-20.1199], GeysirCamp:[64.309939,-20.30445],
  Seljalandsfoss:[63.6156,-19.9886], Gljufrabui:[63.6210,-19.9864], Skogafoss:[63.5321,-19.5114], Kvernufoss:[63.5279,-19.4807],
  Dyrholaey:[63.3994,-19.1260], Reynisfjara:[63.4043,-19.0446], Vik:[63.4186,-19.0060],
  Fjad:[63.7714,-18.1723], Skaftafell:[64.0179,-16.9666], Svina:[64.0000,-16.8800], Fjallsarlon:[64.0164,-16.3649], Jokulsarlon:[64.0476,-16.1791], Diamond:[64.0441,-16.1777],
  Kirkjubaer:[63.7895,-18.0575], Eldhraun:[63.797,-18.061], Kerid:[64.0413,-20.8851], ReykjavikCamp:[64.1476,-21.8755]
};
const day_routes = {
  day1:[pts_route.Reykjavik, pts_route.Thingvellir, pts_route.Geysir, pts_route.Gullfoss, pts_route.GeysirCamp],
  day2:[pts_route.GeysirCamp, pts_route.Seljalandsfoss, pts_route.Gljufrabui, pts_route.Skogafoss, pts_route.Kvernufoss, pts_route.Skogafoss],
  day3:[pts_route.Skogafoss, pts_route.Dyrholaey, pts_route.Reynisfjara, pts_route.Vik, pts_route.Fjad, pts_route.Skaftafell],
  day4:[pts_route.Skaftafell, pts_route.Svina, pts_route.Fjallsarlon, pts_route.Jokulsarlon, pts_route.Diamond, pts_route.Kirkjubaer],
  day5:[pts_route.Kirkjubaer, pts_route.Eldhraun, pts_route.Kerid, pts_route.ReykjavikCamp]
};
const route_times = {};
for (const [d, pts] of Object.entries(day_routes)) route_times[d] = await osrmRouteTime2(pts);
console.log(JSON.stringify(route_times, null, 2));")

